  ('pukao-7ec62a85-moex-00214', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-111-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '行政處分經訴願決定撤銷後，原行政處分機關須重為處分者，下列敘述何者錯誤？', '["訴願決定如係指明事件之事實尚欠明瞭，原處分機關查明事實後，亦不得再為內容相同之處分", "原處分機關重為處分時，應受訴願決定之法律見解拘束", "依實務見解，行政機關重為處分時，無不利益變更禁止原則之適用", "訴願決定意旨應包括作成訴願決定主文所依據之事實及理由"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:43+00:00", "source_pdf_sha1": "d0ebedea4ae8", "answer_pdf_sha1": "cec5c3149dc6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "418", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
